import{z as e}from"zod";export const ExtensionCapabilitySchema=e.enum(["pipeline-hook","narrative-processor","custom-agent","lorebook-source","export-format"]),ExtensionManifestSchema=e.object({name:e.string().min(1).regex(/^[a-z0-9-]+(?:\.[a-z0-9-]+)*$/,"Extension name must be lowercase alphanumeric with dots or hyphens"),version:e.string().min(1).regex(/^\d+\.\d+\.\d+(?:[-+].+)?$/,"Version must follow semver format (e.g. 1.0.0)"),description:e.string().min(1),author:e.string().optional(),minCoreVersion:e.string().optional(),capabilities:e.array(ExtensionCapabilitySchema).min(1)});
